// ─── MONSTER SPRITES ──────────────────────────────────────

function MonsterSpriteImpl({type,size=64,anim='float',style={},mode='pixel'}){
  const ref=useRef(null);
  // MONS定義に sprite フィールドがあれば、それを描画用キーとして使う（既存LRなど）
  // MR は sprite なしなので type自体（mr_X）が使われる
  const baseKey=MONS[type]?.sprite||type;
  // mode='art' の場合は _art サフィックス付きキーを優先（MRキャラのみ存在）
  // _art版が存在しない場合は通常のキーにフォールバック
  const spriteKey=(mode==='art'&&SPRITE_IMGS[baseKey+'_art'])?baseKey+'_art':baseKey;
  useEffect(()=>{
    const cv=ref.current;if(!cv)return;
    const ctx=cv.getContext('2d');
    const im=SPRITE_IMGS[spriteKey];
    const draw=()=>{ctx.clearRect(0,0,256,256);if(im&&im.complete&&im.naturalWidth>0)ctx.drawImage(im,0,0,256,256);};
    draw();
    if(im&&!im.complete){
      const onLoad=()=>draw();
      im.addEventListener('load',onLoad,{once:true});
      return ()=>im.removeEventListener('load',onLoad);
    }
  },[spriteKey]);
  // canvas解像度は256にして、art版（192x192元データ）も pixel版（64x64元データ）も綺麗に拡縮
  return <canvas ref={ref} width={256} height={256} style={{width:size,height:size,imageRendering:mode==='pixel'?'pixelated':'auto',...style,animation:anim!=='none'?`${anim} 1.4s ease-in-out infinite`:'none'}}/>;
}
// memo化: type/size/mode が変わらない限り再レンダーしない
const MonsterSprite=memo(MonsterSpriteImpl,(p,n)=>p.type===n.type&&p.size===n.size&&p.anim===n.anim&&p.mode===n.mode);

// ─── NPC PIXEL ART ───────────────────────────────────────
function drawNPC(ctx,ox,oy,type,frame,flip){
  const W=8;
  const p=(rx,ry,c,w=1,h=1)=>{ctx.fillStyle=c;ctx.fillRect(ox+(flip?W-rx-w:rx),oy+ry,w,h)};
  switch(type){
    case'villager':p(2,0,'#f5c5a0',4,4);p(2,0,'#8b5a2b',4,2);p(0,4,'#1e88e5',8,5);p(1,4,'#f5c5a0',1,4);p(6,4,'#f5c5a0',1,4);p(2,9,'#37474f',2,frame?3:5);p(4,9,'#37474f',2,frame?5:3);break;
    case'grandma':p(2,1,'#f0d0b0',4,3);p(1,0,'#d0d0d0',6,3);p(0,4,'#795548',8,5);p(0,4,'#f0d0b0',1,3);p(7,4,'#f0d0b0',1,3);p(2,9,'#5d4037',2,frame?4:5);p(4,9,'#5d4037',2,frame?5:4);p(7,5,'#bcaaa4',1,6);break;
    case'kid':p(2,1,'#ffe0b2',4,3);p(2,1,'#ff8f00',4,2);p(1,4,'#f9a825',6,4);p(1,4,'#ffe0b2',1,3);p(6,4,'#ffe0b2',1,3);p(2,8,'#f57f17',2,frame?3:4);p(4,8,'#f57f17',2,frame?4:3);break;
    case'knight':p(1,0,'#90a4ae',6,4);p(1,1,'#546e7a',6,2);p(0,4,'#78909c',8,5);p(0,4,'#546e7a',1,5);p(7,4,'#546e7a',1,5);p(2,9,'#607d8b',2,frame?4:5);p(4,9,'#607d8b',2,frame?5:4);p(7,2,'#ff9800',1,7);break;
    case'merchant':p(2,0,'#f5c5a0',4,4);p(1,0,'#2e7d32',6,3);p(0,3,'#2e7d32',8,2);p(0,5,'#ff8f00',8,5);p(0,5,'#f5c5a0',1,4);p(7,5,'#f5c5a0',1,4);p(2,10,'#e65100',2,frame?4:5);p(4,10,'#e65100',2,frame?5:4);break;
    case'shopkeeper':p(2,0,'#f5c5a0',4,4);p(2,0,'#5d4037',4,2);p(2,3,'#3d2818',1,1);p(5,3,'#3d2818',1,1);p(0,4,'#ffffff',8,4);p(1,5,'#c41e3a',6,4);p(3,5,'#ffd700',2,1);p(0,4,'#f5c5a0',1,4);p(7,4,'#f5c5a0',1,4);p(2,9,'#37474f',2,frame?3:5);p(4,9,'#37474f',2,frame?5:3);break;
  }
}

// ─── SHOP BACKGROUND ─────────────────────────────────────
function drawShopBG(ctx){
  ctx.imageSmoothingEnabled=false;
  // Sky
  ctx.fillStyle='#b3d9f0';ctx.fillRect(0,0,200,55);
  ctx.fillStyle='#d6eeff';ctx.fillRect(0,0,200,30);
  // Clouds
  ctx.fillStyle='#fff';
  [[18,7,22,5],[60,5,16,4],[110,10,20,5],[155,7,14,4]].forEach(([x,y,w,h])=>{ctx.fillRect(x,y,w,h);ctx.fillRect(x-2,y+2,w+4,h-1)});
  // Left building
  ctx.fillStyle='#9e8070';ctx.fillRect(0,28,55,72);
  ctx.fillStyle='#7a6050';ctx.fillRect(0,24,55,6);
  ctx.fillStyle='#ae9080';ctx.fillRect(2,30,51,70);
  ctx.fillStyle='#87ceeb';ctx.fillRect(5,33,13,11);ctx.fillRect(28,33,13,11);
  ctx.fillStyle='rgba(255,255,255,0.45)';ctx.fillRect(5,33,7,6);ctx.fillRect(28,33,7,6);
  ctx.fillStyle='#5d4037';ctx.fillRect(16,58,20,42);
  // Tree
  ctx.fillStyle='#5d4037';ctx.fillRect(66,48,4,27);
  ctx.fillStyle='#2e7d32';ctx.fillRect(57,30,22,20);ctx.fillRect(60,23,16,14);ctx.fillRect(63,17,10,10);
  ctx.fillStyle='#388e3c';ctx.fillRect(59,27,20,16);
  // Right shop
  ctx.fillStyle='#e8c090';ctx.fillRect(122,22,78,78);
  ctx.fillStyle='#d4a870';ctx.fillRect(118,19,82,5);
  // Roof
  ctx.fillStyle='#8b5e3c';ctx.fillRect(125,14,70,8);ctx.fillRect(128,12,64,4);ctx.fillRect(132,10,56,4);ctx.fillRect(136,8,48,4);
  // Awning
  ctx.fillStyle='#ff7043';ctx.fillRect(118,32,84,8);
  for(let x=120;x<202;x+=10){ctx.fillStyle='rgba(255,255,255,0.35)';ctx.fillRect(x,32,5,8)}
  // Windows
  ctx.fillStyle='#87ceeb';ctx.fillRect(128,44,22,17);ctx.fillRect(166,44,22,17);
  ctx.fillStyle='rgba(255,255,255,0.5)';ctx.fillRect(128,44,11,8);ctx.fillRect(166,44,11,8);
  // Door
  ctx.fillStyle='#5d3a1a';ctx.fillRect(148,68,24,32);
  ctx.fillStyle='#7a5030';ctx.fillRect(150,70,10,28);ctx.fillRect(162,70,9,28);
  ctx.fillStyle='#ffd700';ctx.fillRect(160,84,2,2);
  // Sign
  ctx.fillStyle='#5d3a1a';ctx.fillRect(130,23,60,10);
  ctx.fillStyle='#ffd700';ctx.font='bold 5px monospace';ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.fillText('★ MATERIAL SHOP ★',160,29);
  // Ground
  ctx.fillStyle='#b09060';ctx.fillRect(0,78,200,22);
  for(let x=0;x<200;x+=13)for(let y=78;y<100;y+=7){
    ctx.fillStyle=(Math.floor(x/13)+Math.floor(y/7))%2===0?'#a08050':'#c0a870';
    ctx.fillRect(x,y,12,6);
    ctx.fillStyle='rgba(0,0,0,0.18)';ctx.fillRect(x,y,12,1);ctx.fillRect(x,y,1,6);
  }
  ctx.fillStyle='rgba(255,255,255,0.12)';ctx.fillRect(122,78,78,22);
}

// ─── SHOP INTERIOR (Home画面用・200x140) ─────────────────
function drawShopInterior(ctx){
  ctx.imageSmoothingEnabled=false;
  // ── 上部: 空（屋根なしの店内が見える設定）── 0-10
  const skyG=ctx.createLinearGradient(0,0,0,10);
  skyG.addColorStop(0,'#88c8ff');skyG.addColorStop(1,'#c8e0ff');
  ctx.fillStyle=skyG;ctx.fillRect(0,0,200,10);
  // 雲（小）
  ctx.fillStyle='rgba(255,255,255,0.85)';
  ctx.fillRect(20,3,8,2);ctx.fillRect(22,2,5,1);
  ctx.fillRect(130,5,10,2);ctx.fillRect(133,4,6,1);
  // ── 店の壁（左右）── 10-70
  // 左壁
  ctx.fillStyle='#a8845a';ctx.fillRect(0,10,8,60);
  ctx.fillStyle='#8a6440';ctx.fillRect(0,10,2,60);
  // 右壁
  ctx.fillStyle='#a8845a';ctx.fillRect(192,10,8,60);
  ctx.fillStyle='#8a6440';ctx.fillRect(198,10,2,60);
  // 奥の壁（店内背景）
  ctx.fillStyle='#d4a574';ctx.fillRect(8,10,184,52);
  ctx.fillStyle='#b8895a';for(let y=14;y<60;y+=8)ctx.fillRect(8,y,184,1);
  // 看板（店内側に向けて、奥壁中央）
  ctx.fillStyle='#3d2510';ctx.fillRect(72,14,56,10);
  ctx.fillStyle='#d4a574';ctx.fillRect(73,15,54,8);
  ctx.fillStyle='#3d2510';ctx.font='bold 6px monospace';ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.fillText('★ MY SHOP ★',100,19);
  // 商品棚（奥の壁、最上段）
  ctx.fillStyle='#5d3a1a';ctx.fillRect(8,28,184,2);
  ctx.fillStyle='#3d2510';ctx.fillRect(8,30,184,1);
  const _cols=['#ff5252','#7c4dff','#69f0ae','#ffd740','#40c4ff','#ff80ab','#b388ff','#ffab40','#26c6da'];
  for(let i=0;i<8;i++){
    const x=14+i*22;
    ctx.fillStyle=_cols[i%_cols.length];ctx.fillRect(x,22,5,6);
    ctx.fillStyle='#3d2510';ctx.fillRect(x+1,20,3,2);
    ctx.fillStyle='rgba(255,255,255,0.45)';ctx.fillRect(x+1,23,1,2);
  }
  // 中央ディスプレイテーブル（商品棚の手前、NPCが物色する場所）
  ctx.fillStyle='#5d3a1a';ctx.fillRect(28,44,144,3);
  ctx.fillStyle='#8b5e3c';ctx.fillRect(28,47,144,5);
  ctx.fillStyle='#6b4520';ctx.fillRect(28,51,144,1);
  // テーブル上のミニ商品
  for(let i=0;i<6;i++){
    const x=38+i*22;
    ctx.fillStyle=_cols[(i+3)%_cols.length];ctx.fillRect(x,40,4,4);
    ctx.fillStyle='rgba(255,255,255,0.3)';ctx.fillRect(x,40,1,2);
  }
  // ── カウンター（店主が立つ） ── 60-70
  // カウンター天板
  ctx.fillStyle='#5d3a1a';ctx.fillRect(8,60,184,3);
  // カウンター前面
  ctx.fillStyle='#8b5e3c';ctx.fillRect(8,63,184,7);
  ctx.fillStyle='#6b4520';for(let y=65;y<70;y+=2)ctx.fillRect(8,y,184,1);
  ctx.fillStyle='#a87545';for(let x=20;x<192;x+=24)ctx.fillRect(x,63,1,7);
  // レジ（カウンター右側）
  ctx.fillStyle='#3d2510';ctx.fillRect(150,54,18,8);
  ctx.fillStyle='#5d3a1a';ctx.fillRect(151,55,16,6);
  ctx.fillStyle='#ffd700';ctx.fillRect(154,57,4,2);ctx.fillRect(160,57,4,2);
  // ── 店外: 入口の階段（道から店へ）── 70-86
  ctx.fillStyle='#7a5030';ctx.fillRect(0,70,200,4); // 床縁
  ctx.fillStyle='#a8845a';ctx.fillRect(0,74,200,4); // 階段1段目
  ctx.fillStyle='#8a6440';ctx.fillRect(0,77,200,1);
  ctx.fillStyle='#c8a878';ctx.fillRect(0,78,200,4); // 階段2段目
  ctx.fillStyle='#a08868';ctx.fillRect(0,81,200,1);
  ctx.fillStyle='#d8b888';ctx.fillRect(0,82,200,4); // 階段3段目
  // 入口エントランス（中央付近、暗い影で「入口がある」を表現）
  ctx.fillStyle='rgba(60,30,15,0.35)';ctx.fillRect(78,70,44,16);
  // 入口の前マット
  ctx.fillStyle='rgba(80,40,20,0.45)';ctx.fillRect(82,84,36,2);
  // ── 道路（歩道+車道） ── 86-160
  // 歩道（上）
  ctx.fillStyle='#9a9a9a';ctx.fillRect(0,86,200,8);
  ctx.fillStyle='#7a7a7a';for(let x=0;x<200;x+=12){ctx.fillRect(x,86,1,8);}
  ctx.fillStyle='#6a6a6a';ctx.fillRect(0,93,200,1);
  // 縁石
  ctx.fillStyle='#5a5a5a';ctx.fillRect(0,94,200,2);
  // 車道
  ctx.fillStyle='#3a3a3a';ctx.fillRect(0,96,200,26);
  // 車道の表面ノイズ
  ctx.fillStyle='#4a4a4a';
  for(let i=0;i<20;i++){const x=(i*23+7)%200;const y=98+(i*7)%24;ctx.fillRect(x,y,2,1);}
  // 中央の白線（破線）
  ctx.fillStyle='#e8e8e8';
  for(let x=8;x<200;x+=24){ctx.fillRect(x,108,12,2);}
  // 歩道（下）
  ctx.fillStyle='#5a5a5a';ctx.fillRect(0,122,200,2);
  ctx.fillStyle='#9a9a9a';ctx.fillRect(0,124,200,8);
  ctx.fillStyle='#7a7a7a';for(let x=0;x<200;x+=12){ctx.fillRect(x,124,1,8);}
  // 下の植え込み（緑）
  ctx.fillStyle='#3d6e2a';ctx.fillRect(0,132,200,8);
  ctx.fillStyle='#4d8e3a';for(let x=0;x<200;x+=8){ctx.fillRect(x+2,132,3,3);ctx.fillRect(x,135,4,3);}
  ctx.fillStyle='#5da848';for(let x=0;x<200;x+=10){ctx.fillRect(x+3,133,2,2);}
}

