// 敵スケーリングヘルパー: クエスト章とノード情報から実際のステータスを返す
function getScaledEnemy(enemyKey, chapter, isBoss, nodeMul){
  const base=ENEMIES[enemyKey];
  if(!base)return null;
  const cmul=CHAPTER_MUL[chapter]||1;
  const bmul=isBoss?BOSS_MUL:1;
  const nmul=nodeMul||1;
  const mul=cmul*bmul*nmul;
  return {
    ...base,
    hp:   Math.max(1, Math.floor(base.hp*mul)),
    atk:  Math.max(1, Math.floor(base.atk*mul*0.85)), // 攻撃はやや控えめにスケール（火力インフレ防止）
    def:  Math.max(0, Math.floor(base.def*mul*0.7)),  // 防御も控えめ
    xp:   Math.max(1, Math.floor(base.xp*mul*1.1)),   // 経験値はやや多めに
    gold: Math.max(0, Math.floor(base.gold*mul*1.2)), // ゴールドも多めに
    _scaled:true,
    _mul:mul,
  };
}

