// プレイヤーLvに必要なXP累計（index=Lv-1, [0]はLv1→Lv2に必要なXP）
// Lv30まで既存数値を維持、Lv31以降は緩やかなカーブで延長 (Lv100で約160万XP/Lv)
const PLV_TABLE=(()=>{
  const base=[0,100,250,450,700,1000,1400,1900,2500,3200,4000,5000,6200,7600,9200,11000,13200,15700,18500,21600,25000,29000,33500,38500,44000,50000,57000,65000,74000,84000];
  // Lv30以降は前Lvの1.085倍ペース
  for(let i=30;i<100;i++){base.push(Math.floor(base[i-1]*1.085));}
  return base;
})();
// プレイヤーLvの節目報酬: Lv達成時にプレゼントボックスに自動配布
const PLAYER_LV_REWARDS={
  5:  [{type:'diamond',amount:20,desc:'ダイヤ×20'},{type:'material',amount:1,payload:{key:'awaken_soul'},desc:'覚醒の魂×1'}],
  10: [{type:'diamond',amount:40,desc:'ダイヤ×40'},{type:'material',amount:2,payload:{key:'awaken_soul'},desc:'覚醒の魂×2'},{type:'material',amount:1,payload:{key:'skill_stone'},desc:'スキル石×1'}],
  20: [{type:'diamond',amount:80,desc:'ダイヤ×80'},{type:'material',amount:3,payload:{key:'awaken_soul'},desc:'覚醒の魂×3'},{type:'material',amount:2,payload:{key:'skill_stone'},desc:'スキル石×2'},{type:'key',amount:10,desc:'修行の鍵×10'}],
  30: [{type:'diamond',amount:150,desc:'ダイヤ×150'},{type:'material',amount:5,payload:{key:'awaken_soul'},desc:'覚醒の魂×5'},{type:'material',amount:3,payload:{key:'skill_stone'},desc:'スキル石×3'},{type:'gem',payload:{color:'red',star:5},desc:'紅玉★5'}],
  50: [{type:'diamond',amount:300,desc:'ダイヤ×300'},{type:'material',amount:8,payload:{key:'awaken_soul'},desc:'覚醒の魂×8'},{type:'material',amount:5,payload:{key:'skill_stone'},desc:'スキル石×5'},{type:'gem',payload:{color:'orange',star:6},desc:'琥珀★6'}],
  70: [{type:'diamond',amount:500,desc:'ダイヤ×500'},{type:'material',amount:12,payload:{key:'awaken_soul'},desc:'覚醒の魂×12'},{type:'material',amount:8,payload:{key:'skill_stone'},desc:'スキル石×8'},{type:'gem',payload:{color:'blue',star:6},desc:'蒼玉★6'},{type:'gem',payload:{color:'green',star:6},desc:'翠玉★6'}],
  100:[{type:'diamond',amount:1000,desc:'ダイヤ×1000'},{type:'material',amount:20,payload:{key:'awaken_soul'},desc:'覚醒の魂×20'},{type:'material',amount:15,payload:{key:'skill_stone'},desc:'スキル石×15'},{type:'gem',payload:{color:'purple',star:7},desc:'紫晶★7'}],
};
function addPlayerXP(s,xp){
  let lv=s.playerLv,px=s.playerXp+xp;
  const msgs=[];
  const pendingGifts=[];
  while(lv<PLV_TABLE.length&&px>=(PLV_TABLE[lv]||99999)){
    px-=PLV_TABLE[lv]||99999;lv++;
    msgs.push(`🎉 プレイヤーLv.${lv}！`);
    // 節目報酬: PLAYER_LV_REWARDS に該当があればプレゼントボックスへ
    const rewards=PLAYER_LV_REWARDS[lv];
    if(rewards){
      rewards.forEach((r,i)=>{
        pendingGifts.push({
          id:'gift_plv'+lv+'_'+i+'_'+Date.now().toString(36)+Math.random().toString(36).slice(2,4),
          type:r.type,amount:r.amount||1,payload:r.payload||null,
          title:`Lv.${lv} 達成記念`,
          desc:r.desc||'',
          from:'プレイヤーランク',
          createdAt:Date.now(),
          expiresAt:Date.now()+30*86400000, // 30日期限
        });
      });
      msgs.push(`🎁 Lv.${lv} 達成報酬がプレゼントBOXに届いた！`);
    }
  }
  const newGifts=pendingGifts.length>0?[...pendingGifts,...(s.giftBox||[])]:(s.giftBox||[]);
  return{...s,playerLv:lv,playerXp:px,giftBox:newGifts,toast:msgs.length?msgs[msgs.length-1]:s.toast};
}

// セーブデータを安全にマイグレーション（コードが変わっても重要データを維持）
function migrateSave(p){
  // モンスターデータを正規化（知らないtypeや壊れたデータを除去・補完）
  // 旧装備形式（slot:keyの文字列）と新形式（slot:eq_id）を両対応
  const mons=(p.monsters||[]).map(m=>{
    if(!MONS[m.type])return null;
    return{
      id:m.id||Date.now()+Math.random()*9999,
      type:m.type,
      name:m.name||MONS[m.type].name,
      level:m.level||1,
      xp:m.xp||0,
      lb:m.lb||0,
      awaken:m.awaken||0,
      skillLv:m.skillLv||1,
      rarity:m.rarity&&RO.includes(m.rarity)?m.rarity:MONS[m.type].rarity,
      // 後でinventory反映後に再度フィルタするため、ここでは生のままコピー
      equip:{hat:m.equip?.hat||null, acc:m.equip?.acc||null, wpn:m.equip?.wpn||null},
      // 宝石装備（5色のスロット、旧データには存在しないので空で初期化）
      gems:{
        red:m.gems?.red||null,orange:m.gems?.orange||null,blue:m.gems?.blue||null,
        green:m.gems?.green||null,purple:m.gems?.purple||null,
      },
      protected:!!m.protected,
    };
  }).filter(Boolean);

  // 素材は既知のキーのみ保持
  const allMaterials={...Object.fromEntries(Object.keys(ITEMS).map(k=>[k,0])),...p.materials||{}};
  const materials=Object.fromEntries(Object.entries(allMaterials).filter(([k])=>ITEMS[k]));

  // 装備インベントリ：旧形式（文字列配列）か新形式（オブジェクト配列）を判別
  let equipInventory=[];
  const rawInv=p.equipInventory||[];
  // 旧→新 変換用キーマップ（旧装備キーから新装備キーへ）
  const oldKeyMap={
    'ribbon':'slime_crown','flowerhat':'thorn_crown','crown':'flame_crown','starcrown':'divine_crown',
    'clover':'skull_charm','heartgem':'amethyst_jewel','moonstone':'flame_band','rainbow':'crystal_ward',
    'wand':'thorn_mace','lightning':'amethyst_orb','sword':'spike_orb','orb':'void_crystal',
    'catears':'ghost_hood','witch_hat':'void_crown','angel_halo':'frost_crown','fairy_wings':'claw_amulet',
    'dragonscale':'skull_armor','starjewel':'ancient_relic','ice_staff':'ember_pot','fire_sword':'flame_orb',
    'holy_bow':'bone_staff','poison_dagger':'skull_pot',
    // v5期の旧名（一部削除されたもの→新装備にマッピング）
    'amethyst_ring':'amethyst_jewel','skull_pendant':'skull_charm','skull_ring':'skull_charm',
    'void_ring':'skull_armor','jade_ring':'skull_charm','bone_ring':'skull_charm',
    'thorn_mace':'rock_mace','crystal_blade':'frost_blade','void_orb':'void_crystal',
    'divine_orb':'divine_crown','bone_staff':'ember_pot','skull_wand':'skull_pot','amethyst_orb':'amethyst_orb',
  };
  const normalizeKey=(k)=>EQUIP[k]?k:(EQUIP[oldKeyMap[k]]?oldKeyMap[k]:null);
  for(const item of rawInv){
    if(typeof item==='string'){
      // 旧文字列形式 → 新形式に変換
      const newKey=normalizeKey(item);
      if(newKey)equipInventory.push({id:genEquipId(),key:newKey,lv:1,lb:0});
    } else if(item && typeof item==='object' && item.key && EQUIP[item.key]){
      equipInventory.push({
        id:item.id||genEquipId(),
        key:item.key,
        lv:Math.max(1, item.lv||1),
        lb:Math.max(0, item.lb||0),
        rarityOverride:item.rarityOverride||null,
      });
    }
  }

  // monster.equipが旧形式（key文字列）の場合: 新装備IDに置換 or null
  // 新形式（eq_xxxの装備ID）の場合: そのインベントリにあれば維持、なければnull
  const inventoryIds = new Set(equipInventory.map(e=>e.id));
  mons.forEach(m=>{
    ['hat','acc','wpn'].forEach(slot=>{
      const v = m.equip[slot];
      if(!v){ m.equip[slot] = null; return; }
      if(typeof v === 'string' && v.startsWith('eq_')){
        // 新形式の装備ID
        m.equip[slot] = inventoryIds.has(v) ? v : null;
      } else if(typeof v === 'string'){
        // 旧形式（装備key文字列） → 該当装備をインベントリから探す or 新規追加して紐付け
        const newKey = normalizeKey(v);
        if(!newKey){ m.equip[slot] = null; return; }
        let existing = equipInventory.find(e => e.key === newKey && !Array.from(inventoryIds).some(id=>id===e.id&&Object.values(mons.flatMap(mm=>Object.values(mm.equip||{}))).includes(id)));
        if(!existing){
          existing = {id: genEquipId(), key: newKey, lv: 1, lb: 0};
          equipInventory.push(existing);
          inventoryIds.add(existing.id);
        }
        m.equip[slot] = existing.id;
      } else {
        m.equip[slot] = null;
      }
    });
  });

  // ショップ出品は既知素材のみ保持
  const listings=(p.shop?.listings||[]).filter(l=>ITEMS[l.itemKey]&&l.qty>0&&l.price>0);

  return{
    ...DEFAULT_STATE,
    coins:typeof p.coins==='number'?p.coins:DEFAULT_STATE.coins,
    monsters:mons.length>0?mons:DEFAULT_STATE.monsters,
    party:(()=>{
      // 旧形式（数値=メインモンスターID）→ 新形式（{main,subs}）に変換
      if(typeof p.party==='number'){
        return{main:p.party, subs:[null,null,null,null]};
      }
      if(p.party&&typeof p.party==='object'){
        const main=p.party.main||(mons[0]?.id||1);
        const subs=Array.isArray(p.party.subs)?p.party.subs.slice(0,4):[];
        while(subs.length<4)subs.push(null);
        // 存在しないIDはnullに置換、メインと重複するサブもnullに
        const validSubs=subs.map(sid=>{
          if(sid===null||sid===undefined)return null;
          if(sid===main)return null;
          return mons.find(m=>m.id===sid)?sid:null;
        });
        return{main,subs:validSubs};
      }
      return{main:mons[0]?.id||1, subs:[null,null,null,null]};
    })(),
    materials,
    equipInventory:equipInventory.length>0?equipInventory:_initialEquip(),
    // 宝石インベントリ（旧セーブには存在しない → 空配列）
    gems:Array.isArray(p.gems)?p.gems.filter(g=>g&&g.id&&GEM_COLORS.includes(g.color)&&g.star>=1&&g.star<=10):[],
    // ダイヤ通貨（旧セーブには存在しない → 0）
    diamonds:typeof p.diamonds==='number'?p.diamonds:0,
    // 図鑑（リセット遡及処理: 図鑑実装初期にダイヤを取り損ねた既存モンスター分を遡及付与）
    dex:(()=>{
      const existingM=Array.isArray(p.dex?.monsters)?p.dex.monsters.filter(t=>MONS[t]):[];
      const existingE=Array.isArray(p.dex?.enemies)?p.dex.enemies.filter(t=>ENEMIES[t]):[];
      const pending=typeof p.dex?.pendingDiamonds==='number'?p.dex.pendingDiamonds:0;
      if(!p.dexResetV1){
        // 1回限りのリセット: 既存図鑑を空にし、所持モンスター分のダイヤを遡及付与
        const uniqueOwnedTypes=new Set();
        mons.forEach(mm=>{if(MONS[mm.type])uniqueOwnedTypes.add(mm.type);});
        const monsList=[...uniqueOwnedTypes];
        return{
          monsters:monsList,
          enemies:[], // 敵は撃退記録がないため遡及不可、今後撃退で登録
          pendingDiamonds:pending+monsList.length*5, // 既存未受取 + 遡及分
          claimedRewards:{monsters:[],enemies:[]},
          enemyDefeats:{},
        };
      }
      // 通常運用: 既存dexを維持し、所持モンスターのうち未登録のものをマージ（ダイヤなし）
      mons.forEach(mm=>{if(MONS[mm.type]&&!existingM.includes(mm.type))existingM.push(mm.type);});
      const existingDefeats=p.dex?.enemyDefeats&&typeof p.dex.enemyDefeats==='object'?p.dex.enemyDefeats:{};
      // 有効なENEMIESキーのみ保持
      const cleanedDefeats={};
      Object.entries(existingDefeats).forEach(([k,v])=>{if(ENEMIES[k]&&typeof v==='number'&&v>0)cleanedDefeats[k]=v;});
      return{
        monsters:existingM,enemies:existingE,pendingDiamonds:pending,
        claimedRewards:{
          monsters:Array.isArray(p.dex?.claimedRewards?.monsters)?p.dex.claimedRewards.monsters:[],
          enemies:Array.isArray(p.dex?.claimedRewards?.enemies)?p.dex.claimedRewards.enemies:[],
        },
        enemyDefeats:cleanedDefeats,
      };
    })(),
    dexResetV1:true, // 遡及処理完了フラグ（次回以降はスキップ）
    // プレゼントボックス（期限付き、起動時に期限切れを自動削除）
    giftBox:(()=>{
      const arr=Array.isArray(p.giftBox)?p.giftBox:[];
      const now=Date.now();
      const filtered=arr.filter(g=>g&&g.id&&g.type&&(!g.expiresAt||g.expiresAt>now));
      // v2.0.11 リリース記念ギフト配布（1回限り）
      if(!p.giftReleaseV1){
        filtered.unshift({
          id:'gift_release_'+now.toString(36),type:'diamond',amount:30,
          title:'プレゼントボックス機能リリース記念',
          desc:'プレゼントボックス機能の追加を記念して、ダイヤ30個をプレゼント！',
          from:'運営',createdAt:now,expiresAt:now+7*86400000, // 7日期限
        });
      }
      return filtered;
    })(),
    giftReleaseV1:true,
    // ガチャ天井カウンタ（旧セーブには存在しない → 0で初期化）
    gachaPity:{
      sinceSR:typeof p.gachaPity?.sinceSR==='number'?p.gachaPity.sinceSR:0,
      sinceUR:typeof p.gachaPity?.sinceUR==='number'?p.gachaPity.sinceUR:0,
      sinceLR:typeof p.gachaPity?.sinceLR==='number'?p.gachaPity.sinceLR:0,
    },
    diamondPity:{
      sinceSR:typeof p.diamondPity?.sinceSR==='number'?p.diamondPity.sinceSR:0,
      sinceUR:typeof p.diamondPity?.sinceUR==='number'?p.diamondPity.sinceUR:0,
      sinceLR:typeof p.diamondPity?.sinceLR==='number'?p.diamondPity.sinceLR:0,
    },
    diamondStamp:{
      count:typeof p.diamondStamp?.count==='number'?Math.max(0,Math.min(10,p.diamondStamp.count)):0,
    },
    mrTickets:typeof p.mrTickets==='number'?Math.max(0,p.mrTickets):0,
    viewedStories:p.viewedStories&&typeof p.viewedStories==='object'?p.viewedStories:{},
    // デイリーミッション（旧セーブには存在しない → 空で初期化、初回ログイン時に自動生成）
    daily:{
      date:p.daily?.date||null,
      loginStreak:typeof p.daily?.loginStreak==='number'?p.daily.loginStreak:0,
      lastLogin:p.daily?.lastLogin||null,
      missions:Array.isArray(p.daily?.missions)?p.daily.missions.filter(m=>m&&m.id&&m.type):[],
      bonusClaimed:!!p.daily?.bonusClaimed,
    },
    shop:{listings,pendingGold:p.shop?.pendingGold||0,autoList:!!p.shop?.autoList},
    facilities:p.facilities||{},
    playerLv:p.playerLv||1,
    playerXp:p.playerXp||0,
    keys:typeof p.keys==='number'?p.keys:0,
    clearedQuests:(()=>{
      const c={...(p.clearedQuests||{})};
      // 旧キー story_X_boss → 新キー story_X_8 への移行
      for(let ch=1;ch<=6;ch++){
        if(c[`story_${ch}_boss`]){c[`story_${ch}_8`]=true;delete c[`story_${ch}_boss`];}
      }
      // 旧構造: stage 1-3 + boss(stage 4) → 新stage 1-8、stage 1-3はそのまま、stage 4は8扱い
      // 新ステージ4-7は未クリアになるが、章末を達成していれば次章は開放される
      return c;
    })(),
    settings:{
      battleSpeed:p.settings?.battleSpeed||1,
      animations:p.settings?.animations!==false,
      autoNextNode:p.settings?.autoNextNode!==false,
      confirmSell:p.settings?.confirmSell!==false,
    },
    screen:'home',toast:null,
  };
}

const INIT=()=>{
  try{
    const raw=localStorage.getItem(SAVE_KEY);
    if(raw){
      const p=JSON.parse(raw);
      return migrateSave(p);
    }
  }catch(e){console.warn('セーブデータ読み込み失敗、初期化します',e);}
  return{...DEFAULT_STATE};
};
