function dexProgress(s,kind){
  // kind: 'monsters' | 'enemies'
  const total=kind==='monsters'?Object.keys(MONS).length:Object.keys(ENEMIES).length;
  const known=(s.dex?.[kind]||[]).length;
  return{known,total,pct:total?known/total*100:0};
}
